using System; using System.Data; using System.Windows.Forms; using EduNova.Services; using EduNova.WinForms.Helpers;
namespace EduNova.WinForms.Forms.Timetable
{ public partial class frmTimetableClassView : Form { private readonly TimetableService _svc = new TimetableService(); private readonly ClassSectionService _csSvc = new ClassSectionService(); public frmTimetableClassView() { InitializeComponent(); Load += frmTimetableClassView_Load; Theme.StyleDataGridView(dgvTimetable); SetupGrid(); } private void SetupGrid() { dgvTimetable.Columns.Clear(); dgvTimetable.Columns.Add(new DataGridViewTextBoxColumn { Name = "colPeriod", HeaderText = "Period", Width = 80 }); dgvTimetable.Columns.Add(new DataGridViewTextBoxColumn { Name = "colTime", HeaderText = "Time", Width = 120 }); dgvTimetable.Columns.Add(new DataGridViewTextBoxColumn { Name = "colSubject", HeaderText = "Subject", Width = 180 }); dgvTimetable.Columns.Add(new DataGridViewTextBoxColumn { Name = "colTeacher", HeaderText = "Teacher", Width = 180 }); dgvTimetable.Columns.Add(new DataGridViewTextBoxColumn { Name = "colRoom", HeaderText = "Room", Width = 100 }); }
        private void frmTimetableClassView_Load(object sender, EventArgs e) { try { var cl = _csSvc.GetAll(); cmbClass.DataSource = cl; cmbClass.DisplayMember = "DisplayName"; cmbClass.ValueMember = "ClassSectionId"; } catch { } }
        private void btnLoad_Click(object sender, EventArgs e) { try { int classId = (int)cmbClass.SelectedValue; int day = cmbDay.SelectedIndex + 1; var dt = _svc.GetTimetable(classId, day); dgvTimetable.DataSource = dt; } catch (Exception ex) { MessageBox.Show("Error: " + ex.Message); } } } }
